import type { Hono } from 'hono';
import { config, validateConfig } from '@packages/config';
import { logger } from '@packages/logger';
import type { Logger } from '@packages/runtime';
import { createManager, type Manager } from '@packages/runtime';
import { createApp } from '@services/app';
import { registerRoutes } from '@services/index';

interface InitStep {
  name: string;
  icon: string;
  execute: () => Promise<void> | void;
}

interface ServerConfig {
  hostname: string;
  port: number;
  displayHost: string;
}

interface AppState {
  app?: Hono;
  isShuttingDown: boolean;
}

declare global {
  var __GATEWAY_ORIGIN__: string;
}

const typedLogger = logger as Logger;

// Create Runtime Manager instance with global config
const manager: Manager = createManager(config.worker);

const state: AppState = {
  isShuttingDown: false,
};

const serverConfig: ServerConfig = {
  hostname: '0.0.0.0',
  port: config.port,
  displayHost: 'localhost',
};

function getErrorInfo(error: unknown): { message: string; stack?: string } {
  if (error instanceof Error) {
    return { message: error.message, stack: error.stack };
  }
  return { message: String(error) };
}

async function safeCleanup(
  name: string,
  cleanup: () => Promise<void> | void,
): Promise<boolean> {
  try {
    await cleanup();
    typedLogger.info(`йЙБ?${name} closed successfully`);
    return true;
  } catch (error) {
    typedLogger.warn(`йИњзЛЕзђН  Error shutting down ${name}`, getErrorInfo(error));
    return false;
  }
}

async function shutdownWorkers(): Promise<void> {
  await manager.stopAll();
}

async function gracefulShutdown(signal: string): Promise<void> {
  if (state.isShuttingDown) {
    return;
  }
  state.isShuttingDown = true;

  typedLogger.info(`Received ${signal} signal, starting graceful shutdown...`);

  const cleanupTasks = [
    { name: 'Workers', cleanup: shutdownWorkers },
  ];

  let hasErrors = false;
  for (const task of cleanupTasks) {
    const success = await safeCleanup(task.name, task.cleanup);
    if (!success) hasErrors = true;
  }

  if (hasErrors) {
    typedLogger.warn('йИњзЛЕзђН  Some resources failed to close, but process will continue to exit');
  } else {
    typedLogger.info('йЙБ?Graceful shutdown completed');
  }

  Deno.exit(hasErrors ? 1 : 0);
}

function stepValidateConfig(): void {
  validateConfig();
}

function stepRegisterSignals(): void {
  const signals: Deno.Signal[] = ['SIGINT'];

  if (Deno.build.os !== 'windows') {
    signals.push('SIGTERM');
  }

  for (const signal of signals) {
    try {
      Deno.addSignalListener(signal, () => void gracefulShutdown(signal));
      typedLogger.debug(`Registered signal listener: ${signal}`);
    } catch (error) {
      typedLogger.warn(`Failed to register signal listener: ${signal}`, getErrorInfo(error));
    }
  }
}

function stepSetupGateway(): void {
  globalThis.__GATEWAY_ORIGIN__ = `http://${serverConfig.displayHost}:${serverConfig.port}`;
  typedLogger.debug('Gateway origin', { origin: globalThis.__GATEWAY_ORIGIN__ });
}

async function stepCreateApp(): Promise<void> {
  const app = await createApp();
  await registerRoutes(app, manager);
  state.app = app;
}

function stepStartServer(): void {
  if (!state.app) {
    throw new Error('Application instance not initialized');
  }

  Deno.serve({
    port: serverConfig.port,
    hostname: serverConfig.hostname,
    onListen: ({ hostname: listenHost, port }) => {
      const displayAddress = listenHost === '0.0.0.0' ? serverConfig.displayHost : listenHost;

      typedLogger.info(`йЙБ?Server running: http://${listenHost}:${port}`);
      typedLogger.info(`й¶ГжСС Platform Admin: http://${displayAddress}:${port}`);
      typedLogger.info(`й¶ГжСЂ App Access: http://${displayAddress}:${port}/apps/:appId`);
    },
  }, state.app.fetch);
}

function getBootstrapSteps(): InitStep[] {
  return [
    {
      name: 'Validate Config',
      icon: 'й¶ГжФ≥',
      execute: stepValidateConfig,
    },
    {
      name: 'Register Signal Handlers',
      icon: 'й¶ГжСЧ',
      execute: stepRegisterSignals,
    },
    {
      name: 'Setup Gateway Origin',
      icon: 'й¶Геѓ™',
      execute: stepSetupGateway,
    },
    {
      name: 'Create Application',
      icon: 'йИњжђЩзђН',
      execute: stepCreateApp,
    },
    {
      name: 'Start HTTP Server',
      icon: 'й¶ГжЃМ',
      execute: stepStartServer,
    },
  ];
}

async function executeStep(step: InitStep, index: number, total: number): Promise<void> {
  const prefix = `[${index + 1}/${total}]`;
  typedLogger.info(`${prefix} ${step.icon} ${step.name}...`);

  try {
    await step.execute();
  } catch (error) {
    typedLogger.error(`${prefix} йЙВ?${step.name} failed`, getErrorInfo(error));
    throw error;
  }
}

function printBootstrapInfo(): void {
  typedLogger.info('й¶ГжЃМ Flash Application Platform starting...');
  typedLogger.info('йИє?.repeat(50));
  typedLogger.info(`й¶ГжСЭ Environment: ${config.env}`);
  typedLogger.info(`й¶Геѓ™ Port: ${config.port}`);
  typedLogger.info(`й¶ГжРІ Apps Directory: ${config.paths.apps}`);
  typedLogger.info('йИє?.repeat(50));
}

async function bootstrap(): Promise<void> {
  printBootstrapInfo();

  const steps = getBootstrapSteps();

  for (let i = 0; i < steps.length; i++) {
    await executeStep(steps[i], i, steps.length);
  }

  typedLogger.info('йИє?.repeat(50));
  typedLogger.info('йЙБ?Platform started successfully');
  typedLogger.info('йИє?.repeat(50));
}

async function main(): Promise<void> {
  try {
    await bootstrap();
  } catch (error) {
    typedLogger.error('йИє?.repeat(50));
    typedLogger.error('йЙВ?Application startup failed', getErrorInfo(error));
    typedLogger.error('йИє?.repeat(50));
    Deno.exit(1);
  }
}

main();

