export function createApp() {
  const app = new Hono();

  // Simplified request logger
  app.use('*', async (c, next) => {
    const start = Date.now();
    await next();
    const ms = Date.now() - start;
    logger.info(`${c.req.method} ${c.req.path} ${c.res.status} - ${ms}ms`);
  });
  app.use(
    '*',
    cors({
      origin: '*',
      credentials: true,
    }),
  );

  app.get('/health', (c) => {
    const hostname = Deno.env.get('HOSTNAME') || 'unknown';
    const nodeId = Deno.env.get('NODE_ID') || '';
    const taskSlot = Deno.env.get('TASK_SLOT') || '';
    const isSwarm = hostname.includes('.');

    const health: {
      status: string;
      timestamp: string;
      uptime: number;
      components: Record<string, unknown>;
    } = {
      status: 'UP',
      timestamp: new Date().toISOString(),
      uptime: Math.floor(performance.now() / 1000),
      components: {},
    };

    if (isSwarm) {
      health.components.swarm = {
        status: 'UP',
        details: {
          hostname,
          nodeId,
          taskSlot,
        },
      };
    }

    return c.json(health);
  });

  app.onError(errorMiddleware);

  app.notFound(async (c) => {
    try {
      const templatePath = join(Deno.cwd(), 'resources', 'templates', '404.html');
      const html = await Deno.readTextFile(templatePath);
      return new Response(html, {
        status: 404,
        headers: { 'Content-Type': 'text/html; charset=utf-8' },
      });
    } catch {
      return c.json({ error: 'Not Found' }, 404);
    }
  });

  logger.info('йЙБ?Hono app initialized');
  return app;
}

