/**
 * Registry module
 *
 * Provides NPM package loading, registry management, and application management functionality.
 *
 * @module packages/registry
 */

import { join } from 'node:path';
import { logger } from '@packages/logger';
import { config } from '@packages/config';
import { resolveNpmAuthorizationHeader } from './npmAuthorization.ts';
import { pathExists } from '@packages/storage';

// йПВеЫ¶жђҐзїѓиН§з≤ЇзАЫж®ЇеБНйР©з®њеПІйНСиК•жЪЯ
const registryPath = join(Deno.cwd(), config.paths.storage, 'registry');

async function ensureRegistryDir(): Promise<void> {
  try {
    await Deno.mkdir(registryPath, { recursive: true });
  } catch (error) {
    const err = error as Error;
    logger.warn(`Failed to create registry directory: ${err.message}`);
  }
}

async function getRegistryFilePath(appName: string): Promise<string> {
  await ensureRegistryDir();
  return join(registryPath, `${appName}.json`);
}

async function getAppFromRegistry(appName: string): Promise<any | null> {
  try {
    const filePath = await getRegistryFilePath(appName);
    if (!(await pathExists(filePath))) {
      return null;
    }
    const content = await Deno.readTextFile(filePath);
    return JSON.parse(content);
  } catch (error) {
    const err = error as Error;
    logger.warn(`Failed to get app from registry: ${err.message}`, { appName });
    return null;
  }
}

async function deleteAppFromRegistry(appName: string): Promise<void> {
  try {
    const filePath = await getRegistryFilePath(appName);
    if (await pathExists(filePath)) {
      await Deno.remove(filePath);
    }
  } catch (error: any) {
    logger.warn(`Failed to delete app from registry: ${error.message}`, { appName });
  }
}

async function listAppsFromRegistry(): Promise<any[]> {
  try {
    await ensureRegistryDir();
    const entries = await Deno.readDir(registryPath);
    const apps: any[] = [];
    
    for await (const entry of entries) {
      if (entry.isFile && entry.name.endsWith('.json')) {
        const appName = entry.name.replace('.json', '');
        const appInfo = await getAppFromRegistry(appName);
        if (appInfo) {
          apps.push(appInfo);
        }
      }
    }
    
    return apps;
  } catch (error: any) {
    logger.error(`Failed to list apps from registry: ${error.message}`);
    return [];
  }
}

export interface Permission {
  appId?: string;
  name: string;
  displayName: string;
  type: 'api';
  resource: string;
  method: string;
  description: string;
  assignedRoles: string[];
  assignedUsers: string[];
}

export interface AppManifest {
  id: string;
  name: string;
  version?: string;
  description?: string;
  icon?: string;
  pages?: unknown[];
  [key: string]: unknown;
}

export interface AppRegistryInfo {
  id: string;
  dirName: string;
  packageName?: string | null;
  version: string;
  installTime: string;
  updateTime: string;
  source: 'npm' | 'local';
  status: string;
  manifest: AppManifest;
}

export interface PackageDist {
  tarball: string;
  shasum?: string;
  integrity?: string;
}

export interface PackageVersion {
  name: string;
  version: string;
  dist: PackageDist;
  [key: string]: unknown;
}

export interface PackageMetadata {
  name: string;
  'dist-tags': { [tag: string]: string };
  versions: { [version: string]: PackageVersion };
  [key: string]: unknown;
}

function getAction(method: string): string {
  const m = method.toUpperCase();
  switch (m) {
    case 'GET': return 'read';
    case 'POST': return 'create';
    case 'PUT':
    case 'PATCH': return 'update';
    case 'DELETE': return 'delete';
    default: return 'execute';
  }
}

function getActionLabel(method: string): string {
  const m = method.toUpperCase();
  switch (m) {
    case 'GET': return 'Read';
    case 'POST': return 'Create';
    case 'PUT':
    case 'PATCH': return 'Update';
    case 'DELETE': return 'Delete';
    default: return 'Execute';
  }
}

async function parseHttpJson(packageDir: string, appId: string): Promise<Permission[]> {
  const httpJsonPath = join(packageDir, 'http.json');
  try {
    await Deno.stat(httpJsonPath);
  } catch {
    return [];
  }

  try {
    const content = await Deno.readTextFile(httpJsonPath);
    const data = JSON.parse(content);
    if (!data.routes || !Array.isArray(data.routes)) {
      return [];
    }

    return data.routes.map((route: any) => {
      const method = route.method || 'GET';
      const path = route.path || '/';
      
      const parts = path.split('/').filter((p: string) => p && !p.startsWith(':'));
      const resourceName = parts.length > 0 ? parts[parts.length - 1] : 'root';
      
      const action = getAction(method);
      const actionLabel = getActionLabel(method);
      
      const name = `${resourceName}.${action}`;
      const displayName = `${actionLabel} ${resourceName}`;
      
      return {
        appId,
        name,
        displayName,
        type: 'api',
        resource: path,
        method,
        description: route.description || `Allow ${displayName}`,
        assignedRoles: Array.isArray(route.roles) ? route.roles : [],
        assignedUsers: Array.isArray(route.users) ? route.users : [],
      };
    });
  } catch (error: any) {
    logger.warn(`Failed to parse http.json for app ${appId}`, { error: error.message });
    return [];
  }
}

async function submitPermissions(appId: string, permissions: Permission[]): Promise<void> {
  const targetUrl = `${config.mspbots.gatewayUrl}/apps/mb-platform-user/api/app/permissions`;
  try {
    const response = await fetch(targetUrl, {
      method: 'POST',
      headers: {
        'Content-Type': 'application/json'
      },
      body: JSON.stringify({
        appId,
        permissions,
      }),
    });
    
    if (!response.ok) {
      logger.warn(`Failed to submit permissions for ${appId}`, {
        status: response.status,
        text: await response.text(),
      });
    } else {
      logger.info(`Submitted permissions for ${appId} to mb-platform-user`);
    }
  } catch (error: any) {
    logger.warn(`Error submitting permissions for ${appId}`, { error: error.message });
  }
}

// NPM Registry Client

/**
 * NPM Registry API client class
 *
 * Used to interact with NPM Registry, retrieve package metadata and download
 * tarball files.
 */
export class NPMRegistry {
  registryUrl: string;

  /**
   * Create NPM Registry client instance
   *
   * @param {string} registryUrl - Registry URL
   */
  constructor(registryUrl: string) {
    this.registryUrl = registryUrl;
  }

  /**
   * Get full package metadata
   *
   * @param {string} packageName - Package name, supports scoped packages (e.g. @mbaiapp/ai-chat)
   * @returns {Promise<PackageMetadata>} Complete package metadata object
   * @throws {Error} If the package does not exist or the request fails
   */
  async getPackageMetadata(packageName: string): Promise<PackageMetadata> {
    try {
      const encodedName = encodeURIComponent(packageName);
      const url = `${this.registryUrl}/${encodedName}`;

      logger.debug(`Fetching package metadata: ${url}`);

      const authorization = await resolveNpmAuthorizationHeader(url);
      const headers: Record<string, string> = {
        'Accept': 'application/json',
      };
      if (authorization) {
        headers['Authorization'] = authorization;
      }

      const response = await fetch(url, {
        headers,
      });

      if (!response.ok) {
        if (response.status === 404) {
          throw new Error(`Package "${packageName}" not found in registry`);
        }
        throw new Error(
          `Failed to fetch package metadata: ${response.status} ${response.statusText}`,
        );
      }

      const metadata = await response.json();
      return metadata as PackageMetadata;
    } catch (error: any) {
      logger.error(`Failed to get package metadata for ${packageName}`, {
        error: error.message,
      });
      throw error;
    }
  }

  /**
   * Get information for a specific package version
   *
   * Resolves the version (supports the 'latest' tag) and returns version
   * details and tarball URL.
   *
   * @param {string} packageName - Package name
   * @param {string} version - Version, supports 'latest' or an explicit version like '1.0.0'
   * @returns {Promise<PackageVersion & { tarball: string }>} Version information object
   * @throws {Error} If the version does not exist or the package has no 'latest' tag
   */
  async getPackageVersion(packageName: string, version = 'latest'): Promise<{
    name: string;
    version: string;
    dist: PackageDist;
    tarball: string;
  }> {
    try {
      const metadata = await this.getPackageMetadata(packageName);

      let actualVersion: string;
      if (version === 'latest') {
        actualVersion = metadata['dist-tags']?.latest;
        if (!actualVersion) {
          throw new Error(`Package "${packageName}" has no "latest" tag`);
        }
      } else {
        actualVersion = version;
      }

      const versionInfo = metadata.versions?.[actualVersion];
      if (!versionInfo) {
        throw new Error(`Version "${actualVersion}" not found for package "${packageName}"`);
      }

      logger.debug(`Resolved ${packageName}@${version} to ${actualVersion}`);

      return {
        name: packageName,
        version: actualVersion,
        dist: versionInfo.dist,
        tarball: versionInfo.dist?.tarball,
      };
    } catch (error: any) {
      logger.error(`Failed to get version info for ${packageName}@${version}`, {
        error: error.message,
      });
      throw error;
    }
  }

  /**
   * Download tarball file to the specified path
   *
   * @param {string} tarballUrl - Tarball download URL
   * @param {string} destPath - Destination file path
   * @returns {Promise<void>}
   * @throws {Error} If the download fails
   */
  async downloadTarball(tarballUrl: string, destPath: string): Promise<void> {
    try {
      logger.debug(`Downloading tarball: ${tarballUrl}`);

      const authorization = await resolveNpmAuthorizationHeader(tarballUrl);
      const response = await fetch(tarballUrl, {
        headers: authorization ? { Authorization: authorization } : undefined,
      });

      if (!response.ok) {
        throw new Error(`Failed to download tarball: ${response.status} ${response.statusText}`);
      }

      const arrayBuffer = await response.arrayBuffer();
      const data = new Uint8Array(arrayBuffer);

      await Deno.writeFile(destPath, data);

      logger.debug(`Tarball downloaded to: ${destPath}`);
    } catch (error: any) {
      logger.error(`Failed to download tarball from ${tarballUrl}`, {
        error: error.message,
      });
      throw error;
    }
  }
}

// NPM Loader

/**
 * NPM application loader class
 *
 * Provides functionality to fetch, extract and validate application packages
 * from the NPM Registry.
 */
export class NPMLoader {
  registry: NPMRegistry;

  /**
   * Create an NPM loader instance
   *
   * @param {string} registryUrl - NPM Registry URL
   */
  constructor(registryUrl: string) {
    this.registry = new NPMRegistry(registryUrl);
  }

  /**
   * Fetch an NPM package
   *
   * Downloads, extracts and validates an NPM package, and returns package
   * information and temporary directory paths. The caller is responsible for
   * calling cleanup to remove temporary files.
   *
   * @param {string} packageName - Package name
   * @param {string} version - Version
   * @param {string} tempPath - Temporary directory base path
   * @param {string} cachePath - Cache directory path
   * @returns {Promise<Object>} Package information object
   * @throws {Error} If fetching or validation fails
   */
  async fetchPackage(
    packageName: string,
    version: string,
    tempPath: string,
    cachePath: string,
  ): Promise<{
    packageName: string;
    version: string;
    manifest: AppManifest;
    tempDir: string;
    packageDir: string;
    tarballPath: string;
  }> {
    const tempId = crypto.randomUUID();
    const tempDir = join(tempPath, tempId);
    let tarballPath = '';

    try {
      logger.info(`Fetching package ${packageName}@${version}`);

      const versionInfo = await this.registry.getPackageVersion(packageName, version);

      if (!versionInfo.tarball) {
        throw new Error(`No tarball URL found for ${packageName}@${version}`);
      }

      await Deno.mkdir(cachePath, { recursive: true });

      const tarballName = `${packageName.replace(/[@\/]/g, '-')}-${versionInfo.version}.tgz`;
      tarballPath = join(cachePath, tarballName);

      await this.registry.downloadTarball(versionInfo.tarball, tarballPath);

      await Deno.mkdir(tempPath, { recursive: true });
      await Deno.mkdir(tempDir, { recursive: true });
      await this.extractTarball(tarballPath, tempDir);

      const packageDir = join(tempDir, 'package');
      const manifestPath = join(packageDir, 'manifest.json');

      let manifest: AppManifest;
      try {
        const manifestText = await Deno.readTextFile(manifestPath);
        manifest = JSON.parse(manifestText);
      } catch (error: any) {
        throw new Error(`Invalid or missing manifest.json: ${error.message}`);
      }

      if (!manifest.id || !manifest.name) {
        throw new Error('manifest.json must contain "id" and "name" fields');
      }

      logger.info(`Package ${packageName}@${versionInfo.version} fetched successfully`);

      return {
        packageName,
        version: versionInfo.version,
        manifest,
        tempDir,
        packageDir,
        tarballPath,
      };
    } catch (error: any) {
      await this.cleanup(tempDir, tarballPath);
      logger.error(`Failed to fetch package ${packageName}@${version}`, {
        error: error.message,
      });
      throw error;
    }
  }

  /**
   * Extract tarball file
   *
   * Uses the tar command to extract a .tgz file into the target directory.
   *
   * @param {string} tarballPath - Tarball file path
   * @param {string} targetDir - Target directory path
   * @returns {Promise<void>}
   * @throws {Error} If extraction fails
   */
  async extractTarball(tarballPath: string, targetDir: string): Promise<void> {
    try {
      logger.debug(`Extracting tarball: ${tarballPath} to ${targetDir}`);

      const process = new Deno.Command('tar', {
        args: ['-xzf', tarballPath, '-C', targetDir],
        stdout: 'piped',
        stderr: 'piped',
      });

      const { code, stderr } = await process.output();

      if (code !== 0) {
        const errorText = new TextDecoder().decode(stderr);
        throw new Error(`tar extraction failed: ${errorText}`);
      }

      logger.debug(`Tarball extracted successfully`);
    } catch (error: any) {
      logger.error(`Failed to extract tarball`, { error: error.message });
      throw error;
    }
  }

  /**
   * Clean up temporary files and directories
   *
   * Deletes the temporary directory and tarball file. Cleanup failures do not
   * throw errors; they are only logged as warnings.
   *
   * @param {string} tempDir - Temporary directory path
   * @param {string} tarballPath - Tarball file path
   * @returns {Promise<void>}
   */
  async cleanup(tempDir?: string, tarballPath?: string): Promise<void> {
    if (tempDir) {
      try {
        await Deno.remove(tempDir, { recursive: true });
        logger.debug(`Cleaned up temp directory: ${tempDir}`);
      } catch (error: any) {
        logger.warn(`Failed to cleanup temp directory: ${tempDir}`, {
          error: error.message,
        });
      }
    }

    if (tarballPath) {
      try {
        await Deno.remove(tarballPath);
        logger.debug(`Cleaned up tarball: ${tarballPath}`);
      } catch (error: any) {
        logger.warn(`Failed to cleanup tarball: ${tarballPath}`, {
          error: error.message,
        });
      }
    }
  }
}

