): Promise<{
  apps: (AppRegistryInfo & { path: string })[];
  total: number;
  page: number;
  limit: number;
}> {
  const { page = 1, limit = 20, search = '' } = options;

  const allApps: (AppRegistryInfo & { path: string })[] = [];

  try {
    const registryApps = await listAppsFromRegistry();

    for (const appInfo of registryApps) {
      allApps.push({
        id: appInfo.id,
        dirName: appInfo.dirName,
        name: appInfo.manifest?.name, // Compatible with frontend usage
        manifest: appInfo.manifest,
        path: join(appsPath, appInfo.id),
        version: appInfo.version,
        source: appInfo.source,
        packageName: appInfo.packageName,
        installTime: appInfo.installTime,
        updateTime: appInfo.updateTime,
        status: appInfo.status,
      } as any); // Temporary cast to match frontend expectations if they differ
    }

    logger.debug(`Loaded ${allApps.length} apps from file system registry`);
  } catch (error: any) {
    logger.error('Failed to load apps from registry', { error: error.message });
  }

  let filteredApps = allApps;
  if (search) {
    const searchLower = search.toLowerCase();
    filteredApps = allApps.filter((app) =>
      app.id.toLowerCase().includes(searchLower) ||
      (app.manifest.name || '').toLowerCase().includes(searchLower)
    );
  }

  const total = filteredApps.length;
  const startIndex = (page - 1) * limit;
  const endIndex = startIndex + limit;
  const paginatedApps = filteredApps.slice(startIndex, endIndex);

  return {
    apps: paginatedApps,
    total,
    page,
    limit,
  };
