    if (directAppInfo) {
      const appId = directAppInfo.id;
      if (!appId) {
        logger.warn('App found but missing id field', { appName: decodedName });
      } else {
        let appPath = null;
        if (directAppInfo.dirName) {
          appPath = join(appsPath, directAppInfo.dirName);
        } else {
          const possibleDirs = [
            decodedName,
            directAppInfo.manifest?.id,
            appId,
          ];

          appPath = await findAppDirectory(appsPath, possibleDirs) || join(appsPath, decodedName);
        }

        return {
          ...directAppInfo,
          id: appId,
          path: appPath,
        };
      }
    }

    // If direct lookup fails, try to find app by manifest name
    const registryApps = await listAppsFromRegistry();

    for (const appInfo of registryApps) {
      if (appInfo.manifest?.name === decodedName) {
        const appId = appInfo.id;
        if (!appId) {
          logger.warn('App found but missing id field', { appName: decodedName });
          continue;
        }

        let appPath = null;
        if (appInfo.dirName) {
          appPath = join(appsPath, appInfo.dirName);
        } else {
          const possibleDirs = [
            decodedName,
            appInfo.manifest?.id,
            appId,
          ];

          appPath = await findAppDirectory(appsPath, possibleDirs) || join(appsPath, decodedName);
        }

        return {
          ...appInfo,
          id: appId,
          path: appPath,
        };
      }
    }

    // If still not found, try to find app by directory name
    try {
      const appDir = join(appsPath, decodedName);
      const stat = await Deno.stat(appDir);
      if (stat.isDirectory) {
        // Check if there's a manifest.json file in the directory
        const manifestPath = join(appDir, 'manifest.json');
        try {
          const manifestText = await Deno.readTextFile(manifestPath);
          const manifest = JSON.parse(manifestText);
          
          if (manifest.id && manifest.name) {
            // Create app info from manifest
            const appInfo: AppRegistryInfo = {
              id: manifest.id,
              dirName: decodedName,
              packageName: null,
              version: manifest.version || '0.0.0',
              installTime: new Date().toISOString(),
              updateTime: new Date().toISOString(),
              source: 'local',
              status: 'running',
              manifest,
            };
            
            // Save app info to registry
            await saveAppToRegistry(decodedName, appInfo);
            
            return {
              ...appInfo,
              path: appDir,
            };
          }
        } catch {
          // No manifest.json file, continue
        }
      }
    } catch {
      // App directory doesn't exist, continue
    }
  } catch (error: any) {
    logger.error('Failed to find app by name', { appName: decodedName, error: error.message });
  }

  return null;
}

/**
 * Install application from NPM Registry
 *
 * Downloads, extracts, validates and installs the application from an NPM package.
 *
 * @param {string} packageName - NPM package name
 * @param {string} version - Version
 * @param {NPMLoader} npmLoader - NPM loader instance
 * @param {Deno.Kv} kv - KV instance
 * @param {string} appsPath - Apps directory path
 * @param {string} tempPath - Temporary directory path
 * @param {string} cachePath - Cache directory path
 * @param {Function} clearModuleCache - Function to clear module cache
 * @returns {Promise<Object>} Installation result
 * @throws {Error} If installation fails
 */
export async function installFromNPM(
  packageName: string,
  version: string,
  appsPath: string,
  tempPath: string,
  cachePath: string,
  clearModuleCache: (appId?: string) => Promise<void> | void,
): Promise<{ appId: string; version: string; packageName: string; permissions?: Permission[] }> {
  const npmLoader = new NPMLoader(config.npm.registryUrl);
  let tempDir: string | undefined = undefined;
  let tarballPath: string | undefined = undefined;

  try {
    logger.info(`Installing app from npm: ${packageName}@${version}`);

    const pkg = await npmLoader.fetchPackage(packageName, version, tempPath, cachePath);
    tempDir = pkg.tempDir;
    tarballPath = pkg.tarballPath;

    const { id: appId, name: appName } = pkg.manifest;
    
    const permissions = await parseHttpJson(pkg.packageDir, appId);
    
    if (permissions.length > 0) {
      await submitPermissions(appId, permissions);
    }

    const appDir = join(appsPath, appName);

    try {
      const existing = await Deno.stat(appDir);

      if (existing.isDirectory) {
        logger.info(`App ${appName} already exists, will be replaced`);
        try {
          await Deno.remove(appDir, { recursive: true });
        } catch (error: any) {
          logger.warn(`Failed to remove existing app directory`, { error: error.message });
        }
      }
    } catch {
      // Directory doesn't exist, continue
    }

    await Deno.mkdir(appDir, { recursive: true });
    await copyFiles(pkg.packageDir, appDir);

    // Check if app already exists
    const existingApp = await getAppFromRegistry(appName);
    
    const appInfo: AppRegistryInfo = {
      id: appId,
      dirName: appName,
      packageName,
      version: pkg.version,
      installTime: existingApp ? existingApp.installTime : new Date().toISOString(),
      updateTime: new Date().toISOString(),
      source: 'npm',
      status: 'running',
      manifest: pkg.manifest,
    };

    // Save app info to file system registry
    await saveAppToRegistry(appName, appInfo);

    await clearModuleCache(appId);

    logger.info(`App ${appId} installed successfully from ${packageName}@${pkg.version}`);

    return { appId, version: pkg.version, packageName, permissions };
  } finally {
    if (tempDir || tarballPath) {
      await npmLoader.cleanup(tempDir, tarballPath);
    }
  }
}

/**
