import { Hono } from 'hono';
import type { AppInfo, Handler, HandlerParams, Query, PathParams, User } from './types.ts';
import { logger } from '@packages/logger';
import { normalizePath } from './utils.ts';

export interface LoadedAppModule {
  app: Hono | Record<string, Handler>;
  serverPath: string;
  lastModified: number;
  processedApp?: Hono;
}

interface ProcessAppModuleOptions {
  appInfo: AppInfo;
  getUser: (c?: any) => User | undefined;
  getBody: (c?: any) => unknown | Promise<unknown>;
  getQuery: (c?: any) => Query;
  getParams: (c?: any) => PathParams;
}

function convertLegacyRoutes(
  routeMap: Record<string, (params: HandlerParams) => unknown | Promise<unknown>>,
  options: ProcessAppModuleOptions
): Hono {
  const { appInfo, getUser, getBody, getQuery, getParams } = options;
  const app = new Hono();

  const parseRoutePath = (path: string): { method: string; routePath: string } => {
    const methodMatch = path.match(/^(GET|POST|PUT|PATCH|DELETE|HEAD|OPTIONS)\s+(.+)$/i);
    if (methodMatch) {
      return { method: methodMatch[1].toLowerCase(), routePath: methodMatch[2].trim() };
    }
    const allMethods = ['get', 'post', 'put', 'patch', 'delete', 'head', 'options'];
    for (const m of allMethods) {
      const prefix = `${m.toUpperCase()} `;
      if (path.toUpperCase().startsWith(prefix)) {
        return { method: m, routePath: path.slice(prefix.length).trim() };
      }
    }
    return { method: 'all', routePath: path };
  };

  for (const [path, handler] of Object.entries(routeMap)) {
    const { method, routePath } = parseRoutePath(path);
    const wrappedHandler = async (c: any) => {
      const user = getUser(c);
      const bodyResult = getBody(c);
      const body = bodyResult instanceof Promise ? await bodyResult : bodyResult;
      const query = getQuery(c);
      const params = getParams(c);
      const effectiveUser = user || { id: 'anonymous', email: '', displayName: 'Guest', roles: [] };
      const handlerParams: HandlerParams = {
        id: appInfo.id,
        name: appInfo.manifest?.name || appInfo.id,
        version: appInfo.manifest?.version || '1.0.0',
        description: appInfo.manifest?.description || '',
        metadata: (appInfo.manifest?.metadata as Record<string, unknown>) || {},
        headers: c?.req?.raw?.headers ? Object.fromEntries(c.req.raw.headers.entries()) : {},
        body,
        query: query || {},
        params: params || {},
        method: c?.req?.method || 'GET',
        pathname: c?.req?.path || '/',
        requestUrl: c?.req?.url || '',
        user: effectiveUser,
      };
      const result = await handler(handlerParams);
      if (result === undefined || result === null) {
        return new Response(null, { status: 204 });
      }
      if (result instanceof Response) {
        return result;
      }
      if (result instanceof Error) {
        return new Response(JSON.stringify({ error: result.message }), {
          status: 500,
          headers: { 'Content-Type': 'application/json' },
        });
      }
      if (typeof result === 'string' || result instanceof String) {
        return new Response(result.toString(), {
          status: 200,
          headers: { 'Content-Type': 'text/plain' },
        });
      }
      return new Response(JSON.stringify(result), {
        status: 200,
        headers: { 'Content-Type': 'application/json' },
      });
    };

    switch (method) {
      case 'get': app.get(routePath, wrappedHandler); break;
      case 'post': app.post(routePath, wrappedHandler); break;
      case 'put': app.put(routePath, wrappedHandler); break;
      case 'patch': app.patch(routePath, wrappedHandler); break;
      case 'delete': app.delete(routePath, wrappedHandler); break;
      default: app.all(routePath, wrappedHandler);
    }
  }
  return app;
}

function isHonoApp(module: unknown): module is Hono {
  if (!module || typeof module !== 'object') return false;
  const obj = module as Record<string, unknown>;
  return typeof obj.get === 'function' && typeof obj.post === 'function';
}

function isLegacyRouteMap(module: unknown): module is Record<string, (params: HandlerParams) => unknown> {
  if (!module || typeof module !== 'object') return false;
  return Object.values(module as Record<string, unknown>).every(v => typeof v === 'function');
}

function processAppModule(
  module: unknown,
  options: ProcessAppModuleOptions
): Hono {
  if (isHonoApp(module)) {
    return module as Hono;
  }

  if (isLegacyRouteMap(module)) {
    return convertLegacyRoutes(module as Record<string, (params: HandlerParams) => unknown>, options);
  }

  if (typeof module === 'function') {
    const serverFn = module as (app: Hono) => Record<string, (params: HandlerParams) => unknown>;
    const honoApp = new Hono();
    const routes = serverFn(honoApp);

    const convertedApp = convertLegacyRoutes(routes as Record<string, (params: HandlerParams) => unknown>, options);

    if (honoApp.routes && honoApp.routes.length > 0) {
      for (const route of honoApp.routes) {
        switch (route.method.toUpperCase()) {
          case 'GET': convertedApp.get(route.path, route.handler as any); break;
          case 'POST': convertedApp.post(route.path, route.handler as any); break;
          case 'PUT': convertedApp.put(route.path, route.handler as any); break;
          case 'PATCH': convertedApp.patch(route.path, route.handler as any); break;
          case 'DELETE': convertedApp.delete(route.path, route.handler as any); break;
          default: convertedApp.all(route.path, route.handler as any);
        }
      }
    }

    return convertedApp;
  }

  throw new Error('Unknown module type: cannot convert to Hono app');
}

export class AppModuleLoader {
  private cache = new Map<string, LoadedAppModule>();
  private loading = new Map<string, Promise<LoadedAppModule>>();

  async load(appInfo: AppInfo): Promise<LoadedAppModule> {
    const appId = appInfo.id;

    const cached = this.cache.get(appId);
    if (cached && !this.needsReload(appId, cached.lastModified)) {
      logger.debug(`Using cached module for app: ${appId}`);
      return cached;
    }

    const existingLoading = this.loading.get(appId);
    if (existingLoading) {
      return await existingLoading;
    }

    const loadPromise = this.doLoad(appInfo);
    this.loading.set(appId, loadPromise);

    try {
      const module = await loadPromise;
      this.cache.set(appId, module);
      logger.info(`Module loaded for app: ${appId}`);
      return module;
    } finally {
      this.loading.delete(appId);
    }
  }

  async loadWithProcessedApp(
    appInfo: AppInfo,
    options: Omit<ProcessAppModuleOptions, 'appInfo'> & { appInfo: AppInfo }
  ): Promise<{ module: LoadedAppModule; processedApp: Hono }> {
    const appId = appInfo.id;
    const module = await this.load(appInfo);

    if (module.processedApp) {
      return { module, processedApp: module.processedApp };
    }

    const processedApp = processAppModule(module.app, options);
    module.processedApp = processedApp;
    logger.info(`Processed app cached for app: ${appId}`);

    return { module, processedApp };
  }

  private async doLoad(appInfo: AppInfo): Promise<LoadedAppModule> {
    const appId = appInfo.id;
    const serverPath = this.getServerPath(appInfo);

    if (!serverPath) {
      throw new Error(`No server path found for app: ${appId}`);
    }

    // Add a random query parameter to bypass Deno's module cache
    // const cacheBust = `?t=${Date.now()}`;
    const module = await import(serverPath);

    const app = module.default;

    if (!app) {
      throw new Error(`No default export found in server.js for app: ${appId}`);
    }

    return {
      app,
      serverPath,
      lastModified: Date.now(),
    };
  }

  private getServerPath(appInfo: AppInfo): string {
    const manifest = appInfo.manifest;
    if (!manifest) {
      return '';
    }

    const metadata = manifest.metadata as Record<string, unknown> | undefined;
    const serverPath = metadata?.serverPath as string | undefined;

    if (serverPath) {
      const basePath = appInfo.path || '';
      return normalizePath(basePath, serverPath);
    }

    const basePath = appInfo.path || '';
    return normalizePath(basePath, 'server.js');
  }

  async needsReload(appId: string, _lastModified: number): Promise<boolean> {
    const cached = this.cache.get(appId);
    if (!cached) {
      return true;
    }

    try {
      let statPath = cached.serverPath;
      if (statPath.startsWith('file://')) {
        statPath = statPath.replace(/^file:\/\/\//, '').replace(/^file:\/\//, '');
        if (statPath.match(/^[a-zA-Z]:/)) {
          statPath = statPath.replace(/\//g, '\\');
        }
      }
      const stat = await Deno.stat(statPath);
      const fileMtime = stat.mtime?.getTime() ?? 0;
      const needsReload = fileMtime > cached.lastModified;
      return needsReload;
    } catch (error) {
      logger.warn('Failed to check file mtime for reload', { appId, error: String(error) });
      return true;
    }
  }

  clearCache(appId?: string): void {
    if (appId) {
      const removed = this.cache.delete(appId);
      if (removed) {
        logger.info(`Cache cleared for app: ${appId}`);
      }
    } else {
      const count = this.cache.size;
      this.cache.clear();
      logger.info(`All cache cleared: ${count} entries removed`);
    }
  }

  getCached(appId: string): LoadedAppModule | undefined {
    return this.cache.get(appId);
  }

  isLoaded(appId: string): boolean {
    return this.cache.has(appId);
  }

  getLoadedApps(): string[] {
    return Array.from(this.cache.keys());
