export async function resolveAppDirByName(
  name: string,
): Promise<{ appDir?: string; appInfo?: AppInfo; error?: string; status?: number }> {
  const kv = (globalThis as unknown as { kv?: Deno.Kv }).kv;
  if (!kv) {
    return { error: 'KV store not initialized', status: 500 };
  }

  const appsDir = join(Deno.cwd(), config.paths.apps);
  const appInfo = await getAppByName(name, appsDir) as AppInfo | null;

  if (!appInfo) {
    return { error: 'App not found', status: 404 };
  }

