  const appDir = join(appsDir, dirName);

  if (!(await pathExists(appDir))) {
    return { error: 'App directory not found', status: 404 };
  }

  return { appDir, appInfo };
}

export async function ensureSchemaEntry(
  appDir: string,
): Promise<{ schemaEntryPath?: string; tempSchemaFile?: string; error?: string; status?: number }> {
  const schemaTsPath = join(appDir, 'schema.ts');
  const schemaJsPath = join(appDir, 'schema.js');

  logger.info('Checking schema path', { appDir, schemaTsPath, schemaJsPath });

  if (await pathExists(schemaTsPath)) {
    return { schemaEntryPath: schemaTsPath };
  } else if (await pathExists(schemaJsPath)) {
    return { schemaEntryPath: schemaJsPath };
  } else {
    logger.error('Schema file not found (checked schema.ts and schema.js)', { appDir });
    try {
      const files: string[] = [];
      for await (const entry of Deno.readDir(appDir)) {
        files.push(entry.name);
      }
      logger.info('Files in app directory:', { appDir, files });
    } catch (e) {
      logger.error('Failed to list files in app directory', { appDir, error: (e as Error).message });
    }
    return { error: 'schema.ts or schema.js not found in app directory', status: 404 };
  }
}

export function extractDbConfig(_appInfo: AppInfo | null | undefined): DbConfig | null {
  const getEnv = (key: string, defaultValue: string) => {
    return Deno.env.get(key) ?? defaultValue;
  };

  const configObj = {
    type: getEnv('DB_TYPE', 'postgresql'),
    host: getEnv('DB_HOST', 'localhost'),
    port: parseInt(getEnv('DB_PORT', '5432'), 10),
    database: getEnv('DB_NAME', 'postgres'),
    user: getEnv('DB_USER', 'postgres'),
    password: getEnv('DB_PASSWORD', ''),
  };

  const requiredFields = ['type', 'host', 'port', 'database', 'user', 'password'];
  const missingFields = requiredFields.filter((field) => {
    const value = configObj[field as keyof typeof configObj];
    return value === undefined || value === null || value === '';
  });

  if (missingFields.length > 0) {
    throw new Error(
      `Missing required database config fields: ${
        missingFields.join(', ')
      } (tried to read from environment variables)`,
    );
  }

  return configObj as DbConfig;
}

export function buildDatabaseUrl(dbConfig: DbConfig): string {
  if (!dbConfig) {
    throw new Error('Database config must not be empty');
  }

  const { type, user, password, host, port, database } = dbConfig;


  if (type === 'postgresql' || type === 'postgres') {
    const encodedPassword = encodeURIComponent(password);
    return `postgres://${user}:${encodedPassword}@${host}:${port}/${database}`;
  }

  throw new Error(`Unsupported database type: ${type}`);
}

export function buildDbEnvVars(dbConfig: DbConfig): Record<string, string> {
  if (!dbConfig) {
    return {};
  }

  return {
    DB_HOST: dbConfig.host,
    DB_PORT: String(dbConfig.port),
    DB_USER: dbConfig.user,
    DB_PASSWORD: dbConfig.password,
    DB_NAME: dbConfig.database,
  };
}

