  const parentEnv = Deno.env.toObject();
  delete parentEnv.DENO_NO_REMOTE;
  delete parentEnv.DENO_CACHE_ONLY;
  return { ...parentEnv, ...extra };
}

export async function runDrizzleKit(options: {
  command: string;
  projectRoot: string;
  drizzleConfigPath: string;
  schemaEntryPath: string;
  outDir: string;
  databaseUrl?: string;
  extraEnv?: Record<string, string>;
  extraArgs?: string[];
}): Promise<{ code: number; stdout: string; stderr: string }> {
  const {
    command,
    projectRoot,
    drizzleConfigPath,
    schemaEntryPath,
    outDir,
    databaseUrl,
    extraEnv,
    extraArgs = [],
  } = options;

  logger.info('runDrizzleKit... ', { appId: extraEnv?.appId, appName: extraEnv?.appName });

  // Convert absolute paths to relative paths from projectRoot to avoid issues with drizzle-kit
  const relativeSchemaPath = relative(projectRoot, schemaEntryPath).replace(/\\/g, '/');
  const relativeOutPath = relative(projectRoot, outDir).replace(/\\/g, '/');

  

  const envDrizzle = buildDrizzleEnv({
    DRIZZLE_APP_ID: extraEnv?.appId || '',
    DRIZZLE_APP_NAME: extraEnv?.appName || '',
    DRIZZLE_SCHEMA_PATH: relativeSchemaPath,
    DRIZZLE_OUT_PATH: relativeOutPath,
    ...(databaseUrl ? { DATABASE_URL: databaseUrl } : {}),
    ...(extraEnv || {}),
  });

  logger.info('run migrate command params', { envDrizzle });

  const cmd = new Deno.Command('deno', {
    cwd: projectRoot,
    env: envDrizzle,
    args: [
      'run',
      '-A',
      'npm:drizzle-kit',
      command,
      `--config=${drizzleConfigPath.replace(/\\/g, '/')}`,
      ...extraArgs,
    ],
    stdout: 'piped',
    stderr: 'piped',
  });

  const output = await cmd.output();
  const decoder = new TextDecoder();
  return {
    code: output.code,
    stdout: decoder.decode(output.stdout),
    stderr: decoder.decode(output.stderr),
  };
}

