import { join } from 'node:path';

/**
 * Check if path exists
 * 
 * @param {string} path - Path to check
 * @returns {Promise<boolean>} Returns true if path exists
 */
export async function pathExists(path: string): Promise<boolean> {
  try {
    await Deno.lstat(path);
    return true;
  } catch {
    return false;
  }
}

/**
 * Alias for pathExists
 */
export const exists = pathExists;

// KV Service functions

let kvInstance: Deno.Kv | null = null;

/**
 * Get KV instance (singleton)
 * 
 * @param {string} kvPath - Path to KV database
 * @returns {Promise<Deno.Kv>} Deno KV instance
 */
async function getKV(kvPath: string): Promise<Deno.Kv> {
  if (!kvInstance) {
    kvInstance = await Deno.openKv(kvPath);
  }
  return kvInstance;
}

/**
 * Validate that the application exists
 * 
 * @param {string} appId - Application identifier
 * @param {string} appsPath - Path to apps directory
 * @throws {Error} If the application does not exist
 */
async function validateApp(appId: string, appsPath: string): Promise<void> {
  const appPath = join(appsPath, appId);
  if (!(await pathExists(appPath))) {
    throw new Error(`APP_NOT_FOUND: App with id '${appId}' not found`);
  }
}

/**
 * List all KV keys of an application
 * 
 * @param {string} appId - Application identifier
 * @param {string} kvPath - Path to KV database
 * @param {string} appsPath - Path to apps directory
 * @param {string} prefix - Key prefix filter
 * @returns {Promise<Object>} Keys listing object
 * @property {string} appId - Application ID
 * @property {string[]} keys - Keys
 * @property {number} total - Total key count
 * @throws {Error} If the application does not exist
 */
export async function listKVKeys(
  appId: string,
  kvPath: string,
  appsPath: string,
  prefix = ''
): Promise<{ appId: string; keys: string[]; total: number }> {
  await validateApp(appId, appsPath);

  const kv = await getKV(kvPath);
  const keys: string[] = [];

  const fullPrefix = ['apps', appId, 'kv', prefix];

  const iter = kv.list({ prefix: fullPrefix });

  for await (const entry of iter) {
    const actualKey = entry.key.slice(3).join(':');
    keys.push(actualKey);
  }

  return {
    appId,
    keys,
    total: keys.length,
  };
}

