 * @returns {Promise<Object>} Cleanup result object
 * @property {string} appId - Application ID
 * @property {number} keysDeleted - Number of deleted keys
 * @throws {Error} If the application does not exist and skipValidation is not set
 */
export async function clearAppKV(
  appId: string,
  kvPath: string,
  appsPath: string,
  options: { skipValidation?: boolean } = {}
): Promise<{ appId: string; keysDeleted: number }> {
  const { skipValidation = false } = options;
  
  if (!skipValidation) {
    await validateApp(appId, appsPath);
  }

  const kv = await getKV(kvPath);

  const keys: Deno.KvKey[] = [];
  const iter = kv.list({ prefix: ['apps', appId, 'kv'] });
  for await (const entry of iter) {
    keys.push(entry.key);
  }

  for (const key of keys) {
    await kv.delete(key);
  }

  return {
    appId,
    keysDeleted: keys.length,
  };
}
